function langFromPath(filePath) {
  const base = filePath.split("/").pop() || "";
  if (base in NAME_LANG) return NAME_LANG[base];
  const ext = (0, import_path.extname)(base);
  if (!ext) return null;
  return EXT_LANG[ext] ?? null;
}

